import pandas as pd


class DateProcessor:
    def __init__(self, fmt='%Y-%m-%d'):
        self.fmt = fmt

    def parse_dates(self, df):
        # BUG: strict format fails on mixed '/'-separated dates
        df['ts'] = pd.to_datetime(df['ts_str'], format=self.fmt)
        return df


def parse_dates(df):
    return DateProcessor().parse_dates(df)


def main():
    df = pd.DataFrame({
        'ts_str': ['2024-01-10', '2024/01/15', '2024-01-20'],
        'value': [1, 2, 3],
    })
    out = parse_dates(df)
    print(out)


if __name__ == '__main__':
    main()
